(window.webpackJsonp=window.webpackJsonp||[]).push([[309],{936:function(r,n){r.exports="\x3c!-- \r\ntitle: 51-图像分类\r\nsort: \r\n--\x3e \r\n# OpenCV图像分类\r\n\r\n## 导入图像\r\n\r\n```python\r\n# 导入opencv-python\r\nimport cv2\r\n\r\n# 读入本地图像文件\r\nimg = cv2.imread('no_exist.png')\r\n\r\n# 校验图像是否导入成功，如果导入失败，就输出提示\r\nif img is None:\r\n    print(\"未能读入图像，请检查图像文件路径是否正确\")\r\n\r\n# 在窗口中显示图像\r\ncv2.imshow(\"Display window\", img)\r\n\r\n# 获取键盘按键动作，如果按下s键，就将图像保存至本地\r\nk = cv2.waitKey(0) # 0表示永久等待键盘按键，15表示等待15毫秒\r\n\r\nif k == ord(\"s\"):\r\n    cv2.imwrite(\"saved_img.png\", img)\r\n    \r\ncv2.destroyAllWindows()\r\n\r\n```\r\n\r\n## 处理视频\r\n\r\n```python\r\n# 导入opencv-python\r\nimport cv2\r\n\r\n# 传入本地视频\r\ncap = cv2.VideoCapture('test.mp4')\r\n\r\n# 校验本地视频是否捕获成功，如果未成功则输出提示\r\nif not cap.isOpened():\r\n    print(\"无法打开视频\")\r\n    exit()\r\n\r\n# 获取视频的宽、高信息，cap.get()传入的参数可以是0-18的整数，也可以设置宽高等信息\r\nprint('WIDTH',cap.get(3))\r\nprint('HEIGHT',cap.get(4))\r\n\r\n# 无限循环，直到触发break跳出\r\nwhile True:\r\n    # 逐帧获取视频画面，返回ret和frame\r\n    # ret的True/False反映是否捕获成功，frame是画面\r\n    ret, frame = cap.read()\r\n    \r\n    # 校验画面帧是否正确捕获，如果未成功则输出提示，跳出循环\r\n    if not ret:\r\n        print(\"无法获取画面帧\")\r\n        break\r\n\r\n    # 对画面帧进行处理\r\n    # 这里是将画面转为灰度图\r\n    gray = cv2.cvtColor(frame, cv2.COLOR_BGR2GRAY)\r\n    \r\n    # 在窗口中显示处理之后的画面\r\n    cv2.imshow('frame_window', gray)\r\n    \r\n    # 获取键盘按键动作，如果按下q键，就跳出循环\r\n    # 25毫秒是恰好的，如果太小，播放速度会很快，如果太大，播放速度会很慢\r\n    if cv2.waitKey(25) == ord('q'):\r\n        break\r\n    \r\n# When everything done, release the capture\r\ncap.release()\r\ncv2.destroyAllWindows()\r\n```\r\n\r\n## 保存视频\r\n\r\n```python\r\n# 导入科学计算库numpy\r\nimport numpy as np\r\n\r\n# 导入opencv-python\r\nimport cv2 as cv\r\n\r\n# 获取摄像头\r\ncap = cv.VideoCapture(0)\r\n\r\n# 指定VideoWriter的fourCC视频编码\r\nfourcc = cv.VideoWriter_fourcc(*'DIVX')\r\n\r\n# 指定输出文件、fourCC视频编码、FPS帧率、画面大小\r\nout = cv.VideoWriter('output.avi', fourcc, 20.0, (640,  480))\r\n\r\nwhile cap.isOpened():\r\n    ret, frame = cap.read()\r\n    if not ret:\r\n        print(\"无法打开摄像头\")\r\n        break\r\n\r\n    # 对画面帧进行处理\r\n    # 这里是将画面翻转   \r\n    frame = cv.flip(frame, 0)\r\n    \r\n    # 将处理后的画面逐帧保存至output文件中\r\n    out.write(frame)\r\n    # 将处理后的画面逐帧显示在窗口中\r\n    cv.imshow('frame', frame)\r\n    # 获取键盘按键动作，如果按下q键，就跳出循环\r\n    if cv.waitKey(1) == ord('q'):\r\n        break\r\n    \r\n# 关闭摄像头、视频保存器、窗口\r\ncap.release()\r\n# out.release()\r\ncv.destroyAllWindows()\r\n\r\n```\r\n\r\n## 总结\r\n\r\n### 图片\r\n\r\n```python\r\n# 导入图像\r\nimg = cv2.imread(path)\r\n# img is None 判断是否导入成功\r\n# 显示图像\r\ncv2.imshow(\"Title\", img)\r\n# 等待按键，0表示永久\r\nk = cv2.waitKey(0)\r\n# 关闭显示窗口\r\ncv2.destroyAllWindows()\r\n# 写入图像\r\ncv2.imwrite(\"Name\", img)\r\n```\r\n\r\n### 摄像头\r\n\r\n```python\r\n# 获取摄像头，0表示编号为1的摄像头\r\ncap = cv2.VideoCapture(0,cv2.CAP_DSHOW)\r\n# 打开摄像头\r\ncap.open(0)\r\n# 读取,flag为读取成功标记，frame为像素字典\r\nflag, frame= cap.read()\r\n'''frame\r\narray([[[ 3,  3,  3],\r\n        [ 3,  3,  3],\r\n        [ 1,  1,  1],\r\n        ...,\r\n'''\r\n# 展示方法与图片一致，延时60ms\r\ncv2.waitKey(60)\r\n# 关闭摄像头\r\ncap.release()\r\n\r\n```\r\n\r\n### 视频\r\n\r\n```python\r\n# 打开视频\r\nvid = cv2.VideoCapture(path)\r\n# 获取视频信息,3为宽，4为高\r\nvid.get(3)\r\n# 获取一帧\r\nret, frame = cap.read()\r\n# 展示方法与图片一致，延时25ms\r\ncv2.waitKey(25)\r\n```\r\n\r\n### 保存视频\r\n\r\n```python\r\n# 指定视频编码\r\nfourcc = cv.VideoWriter_fourcc(*'DIVX')\r\n# 指定输出文件,文件、编码、帧率、画面大小\r\nout = cv.VideoWriter('output.avi', fourcc, 10.0 (640,480))\r\n# 写入\r\nout.write(frame)\r\n```\r\n\r\n"}}]);